import{scaleLinear as d3ScaleLinear}from"d3-scale";import{expect}from"@jest/globals";import builtIn from"./builtIn.js";const width=200,height=100,xDomain=[-5,5],yDomain=[-5,5],xScale=d3ScaleLinear().domain(xDomain).range([0,width]),yScale=d3ScaleLinear().domain(yDomain).range([height,0]);function toBeCloseTo(e,t,a=.001){if(Array.isArray(e)&&Array.isArray(t))return Math.abs(e[0]-t[0])>a||Math.abs(e[1]-t[1])>a?{message:()=>`expected ${this.utils.printReceived(e)} to be within range of `+this.utils.printReceived(t),pass:!1}:{pass:!0};throw new Error("Got and Want must be arrays")}expect.extend({toBeCloseTo:toBeCloseTo}),describe("builtIn sampler",()=>{describe("with linear sampler",()=>{it("should render 2 points for x",()=>{var e={d:{fn:"1000000*x",fnType:"linear"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},nSamples:2},e=builtIn(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(2),expect(e[0][0]).toEqual([-5,-5e6]),expect(e[0][1]).toEqual([5,5e6])}),it("should render 101 points for x^2",()=>{var e={d:{fn:"x^2",fnType:"linear"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},nSamples:101},e=builtIn(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(101),expect(e[0][0]).toEqual([-5,25]),expect(e[0][50]).toEqual([0,0]),expect(e[0][100]).toEqual([5,25])}),it("should render 2 groups for 1/x",()=>{var e={d:{fn:"1/x",fnType:"linear"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},nSamples:1e3},e=builtIn(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(2),expect(e[0].length).toEqual(500),expect(e[1].length).toEqual(500)}),it("should render 0 groups for sqrt(x)",()=>{var e=[-100,-95],t=d3ScaleLinear().domain(e).range([0,width]),a=d3ScaleLinear().domain([-5,5]).range([height,0]),e=builtIn({d:{fn:"sqrt(x)",fnType:"linear"},range:e,xScale:t,yScale:a,xAxis:{type:"linear"},nSamples:1e3});expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(0)})}),describe("with parametric sampler",()=>{it("should render a circle of radius 1",()=>{var e={d:{x:"cos(t)",y:"sin(t)",fnType:"parametric"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},nSamples:1001},e=builtIn(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(1001),expect(e[0][0]).toBeCloseTo([1,0]),expect(e[0][250]).toBeCloseTo([0,1]),expect(e[0][500]).toBeCloseTo([-1,0]),expect(e[0][750]).toBeCloseTo([0,-1]),expect(e[0][1e3]).toBeCloseTo([1,0])})}),describe("with points sampler",()=>{it("should render a cube",()=>{var e={d:{points:[[1,1],[2,1],[2,2],[1,2]],fnType:"points"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},nSamples:4},e=builtIn(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(4),expect(e[0][0]).toBeCloseTo([1,1]),expect(e[0][1]).toBeCloseTo([2,1]),expect(e[0][2]).toBeCloseTo([2,2]),expect(e[0][3]).toBeCloseTo([1,2])})}),describe("with vector sampler",()=>{it("should render a vector",()=>{var e={d:{vector:[2,1],offset:[1,2],fnType:"vector"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},nSamples:2},e=builtIn(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(2),expect(e[0][0]).toBeCloseTo([1,2]),expect(e[0][1]).toBeCloseTo([3,3])})})});